import { describe, it, expect } from 'vitest';
import {
  TIER_BANDWIDTHS,
  TIERS,
  identitySieve,
  verifySieveLaws,
  type SieveOps,
  type Substrate,
} from '../src/sieve-algebra';

// Helper: structural equality on Substrate<string>.
const stringEquals = (
  a: Substrate<string>,
  b: Substrate<string>,
): boolean => a.carrier === b.carrier && a.bandwidth === b.bandwidth;

describe('sieve-algebra: TIER_BANDWIDTHS constants', () => {
  it('matches the Lean tower constants', () => {
    expect(TIER_BANDWIDTHS.decagon).toBe(10);
    expect(TIER_BANDWIDTHS.pleroma).toBe(90);
    expect(TIER_BANDWIDTHS.tritonTriple).toBe(270);
  });

  it('TIERS lists the three tiers in ascending order', () => {
    expect(TIERS).toEqual(['decagon', 'pleroma', 'tritonTriple']);
  });
});

describe('sieve-algebra: identitySieve passes all laws', () => {
  it('verifySieveLaws returns [] on a string-carrier witness', () => {
    const sieve = identitySieve<string>();
    const witness: Substrate<string> = { carrier: 'hello', bandwidth: 5 };
    const failures = verifySieveLaws(sieve, witness, stringEquals);
    expect(failures).toEqual([]);
  });
});

describe('sieve-algebra: executeStretch contract', () => {
  it('returns 3 substrates in tier order (decagon, pleroma, tritonTriple)', () => {
    const sieve = identitySieve<string>();
    const witness: Substrate<string> = { carrier: 'x', bandwidth: 0 };
    const stretch = sieve.executeStretch(witness);

    expect(stretch.length).toBe(3);
    expect(stretch[0]!.bandwidth).toBe(TIER_BANDWIDTHS.decagon);
    expect(stretch[1]!.bandwidth).toBe(TIER_BANDWIDTHS.pleroma);
    expect(stretch[2]!.bandwidth).toBe(TIER_BANDWIDTHS.tritonTriple);
  });
});

describe('sieve-algebra: applyGrounding contract', () => {
  it('sets bandwidth to decagon (10) regardless of input bandwidth', () => {
    const sieve = identitySieve<string>();
    for (const startBw of [0, 5, 42, 90, 270, 999]) {
      const sub: Substrate<string> = { carrier: 'q', bandwidth: startBw };
      const grounded = sieve.applyGrounding(sub);
      expect(grounded.bandwidth).toBe(TIER_BANDWIDTHS.decagon);
    }
  });
});

describe('sieve-algebra: broken sieve fails monotone-bandwidth law', () => {
  it('reports stretch_monotone_bandwidth@1 when stretch is out of order', () => {
    const broken: SieveOps<string> = {
      applyGrounding: (sub) => ({ ...sub, bandwidth: TIER_BANDWIDTHS.decagon }),
      executeStretch: (sub) => [
        { ...sub, bandwidth: TIER_BANDWIDTHS.tritonTriple }, // 270
        { ...sub, bandwidth: TIER_BANDWIDTHS.decagon },      // 10  (drops!)
        { ...sub, bandwidth: TIER_BANDWIDTHS.pleroma },      // 90
      ],
    };
    const witness: Substrate<string> = { carrier: 'w', bandwidth: 0 };
    const failures = verifySieveLaws(broken, witness, stringEquals);
    expect(failures).toContain('stretch_monotone_bandwidth@1');
  });
});

describe('sieve-algebra: non-idempotent sieve fails grounding_idempotent', () => {
  it('reports grounding_idempotent when applyGrounding increments bandwidth', () => {
    const nonIdempotent: SieveOps<string> = {
      applyGrounding: (sub) => ({ ...sub, bandwidth: sub.bandwidth + 1 }),
      executeStretch: (sub) =>
        TIERS.map((t) => ({ ...sub, bandwidth: TIER_BANDWIDTHS[t] })),
    };
    const witness: Substrate<string> = { carrier: 'n', bandwidth: 0 };
    const failures = verifySieveLaws(nonIdempotent, witness, stringEquals);
    expect(failures).toContain('grounding_idempotent');
  });
});

describe('sieve-algebra: stretch ending below tritonTriple fails closure_at_top', () => {
  it('reports closure_at_top when last tier is not at tritonTriple bandwidth', () => {
    const truncated: SieveOps<string> = {
      applyGrounding: (sub) => ({ ...sub, bandwidth: TIER_BANDWIDTHS.decagon }),
      executeStretch: (sub) => [
        { ...sub, bandwidth: TIER_BANDWIDTHS.decagon },
        { ...sub, bandwidth: TIER_BANDWIDTHS.decagon },
      ],
    };
    const witness: Substrate<string> = { carrier: 't', bandwidth: 0 };
    const failures = verifySieveLaws(truncated, witness, stringEquals);
    expect(failures).toContain('closure_at_top');
  });
});
